      out.write("<!-- ===== CUSTOM CURSOR ===== -->\n");
      out.write("<div class=\"cursor-dot\" id=\"cursorDot\"></div>\n");
      out.write("<div class=\"cursor-outline\" id=\"cursorOutline\"></div>\n");
      out.write("\n");
      out.write("<script>\n");
      out.write("    (function () {\n");
      out.write("        // ââ Theme persistence ââââââââââââââââââââââââââââââââââââââââââ\n");
      out.write("        var savedTheme = localStorage.getItem('theme');\n");
      out.write("        if (savedTheme) {\n");
      out.write("            document.documentElement.setAttribute('data-theme', savedTheme);\n");
      out.write("            document.body.setAttribute('data-theme', savedTheme);\n");
      out.write("        }\n");
      out.write("\n");
      out.write("        // ââ Custom cursor ââââââââââââââââââââââââââââââââââââââââââââââ\n");
      out.write("        var dot = document.getElementById('cursorDot');\n");
      out.write("        var outline = document.getElementById('cursorOutline');\n");
      out.write("        if (dot && outline) {\n");
      out.write("            document.addEventListener('mousemove', function (e) {\n");
      out.write("                dot.style.left = e.clientX + 'px';\n");
      out.write("                dot.style.top = e.clientY + 'px';\n");
      out.write("                outline.style.left = e.clientX + 'px';\n");
      out.write("                outline.style.top = e.clientY + 'px';\n");
      out.write("            });\n");
      out.write("            document.addEventListener('mousedown', function () {\n");
      out.write("                dot.style.transform = 'translate(-50%,-50%) scale(1.8)';\n");
